// // This register loads its value only when the load signal is low and resets to 1 when the reset signal is low.
module top_module (
	input clk,
	input reset,
	input load,
	input [7:0] data,
	output reg [7:0] q);always @(posedge clk or posedge reset) begin
		if (reset)
			q <= 8'b00000000;
		else if (load)
			q <= data;
	end

endmodule
